            reinterpret_cast<const float4*>(orth.data_ptr<float>()),
            neg_lr_scale, decay_factor, momentum,
            static_cast<unsigned>(step), N4);
        return;
    }

    const int grid = (N + MUON_MOE_BLOCK - 1) / MUON_MOE_BLOCK;

    AT_DISPATCH_FLOATING_TYPES_AND2(
        at::ScalarType::Half, at::ScalarType::BFloat16,
        param.scalar_type(), "muon_update_q4", ([&] {
        muon_update_q4_kernel<scalar_t><<<grid, MUON_MOE_BLOCK>>>(
